{
    // =========================================================
    //  settings.json  ―  VS Code の「設定ファイル」
    // =========================================================
    // ここに書いた設定は、このワークスペース（フォルダ）を
    // VS Code で開いたときだけ有効になる。
    // 個人のグローバル設定を上書き(オーバーライド)できる。
    // ---------------------------------------------------------

    // ---- ファイルのエンコーディング（文字コード） ----
    // このプロジェクトは Shift_JIS / CP932 のファイルが多いので
    // デフォルトを Shift_JIS にしておく
    "files.encoding": "shiftjis",

    // 「BOM 付き UTF-8 かどうか」を自動判定してくれる
    "files.autoGuessEncoding": true,

    // ---- 改行コード ----
    // Windows プロジェクトなので CRLF（\r\n）をデフォルトにする
    "files.eol": "\r\n",

    // ---- 保存時の自動整形 ----
    // ファイル末尾に必ず空行を1つ入れる（Git diff がきれいになる）
    "files.insertFinalNewline": true,
    // 末尾の無駄な空白を自動削除
    "files.trimTrailingWhitespace": true,

    // ---- 検索・エクスプローラーから除外するフォルダ ----
    // ビルド成果物や中間ファイルのフォルダを非表示にして
    // サイドバーや検索結果をスッキリさせる
    "files.exclude": {
        "**/.vs": true,
        "**/.git": true,
        "**/obj": true,
        "**/bin": true,
        "**/x64/Debug": true,
        "**/x64/Release": true,
        "**/*.suo": true,
        "**/*.user": true
    },

    // 検索時に無視するフォルダ（上とは別に指定できる）
    "search.exclude": {
        "**/obj": true,
        "**/bin": true,
        "**/x64": true,
        "**/.vs": true,
        "**/Debug": true,
        "**/Release": true,
        "**/*.dll": true,
        "**/*.exe": true,
        "**/*.pdb": true
    },

    // ---- タブとインデント ----
    // C/C++ は タブ文字（\t）を使うことが多い
    // 1つのタブの表示幅 = スペース4個分
    "editor.tabSize": 4,
    "editor.detectIndentation": true,

    // ---- エディタの見た目 ----
    // 1行あたりの目安線（ガイドライン）を120文字目に表示
    "editor.rulers": [120],

    // ---- Git 関連 ----
    // 変更があったファイルをエクスプローラーで色付きで表示
    "git.decorations.enabled": true,

    // ---- 言語ごとの個別設定 ----
    // C/C++ ファイルのエンコーディングは Shift_JIS を明示
    "[c]": {
        "files.encoding": "shiftjis"
    },
    "[cpp]": {
        "files.encoding": "shiftjis"
    },
    // C# も同様
    "[csharp]": {
        "files.encoding": "shiftjis"
    },
    // Python（hookスクリプト等）は UTF-8
    "[python]": {
        "files.encoding": "utf8"
    }
}

{
    // =========================================================
    //  extensions.json  ―  「推奨する拡張機能」リスト
    // =========================================================
    // このファイルに書いた拡張機能は、ワークスペースを開いたとき
    // VS Code が「インストールしますか？」とおすすめしてくれる。
    // チームメンバー全員が同じ拡張機能を使えるようにするための仕組み。
    //
    // recommendations   = 「入れた方がいいよ」リスト
    // unwantedRecommendations = 「これは入れないで」リスト
    // ---------------------------------------------------------

    "recommendations": [
        // --- C/C++ 開発に必須 ---
        // Microsoft 公式。コード補完・デバッグ・定義ジャンプなど
        "ms-vscode.cpptools",

        // --- C# 開発に必須 ---
        // Microsoft 公式の C# 拡張。IntelliSense やデバッグ
        "ms-dotnettools.csharp",

        // --- Python（hook スクリプト用） ---
        "ms-python.python",

        // --- Git 関連 ---
        // Git の変更履歴を行ごとに表示（誰がいつ変えたか）
        "eamodio.gitlens",

        // --- エンコーディング ---
        // 文字コードの変換や確認に便利
        "bushick.vscode-encoding",

        // --- 見た目・効率化 ---
        // 対応するカッコを色分け表示（読みやすくなる）
        "coenraads.bracket-pair-colorizer-2",

        // インデントを可視化（レインボー表示）
        "oderwat.indent-rainbow",

        // 末尾の余計な空白を赤くハイライト
        "shardulm94.trailing-spaces",

        // --- ファイル形式 ---
        // XML ファイルの整形・ハイライト
        "dotjoshjohnson.xml",

        // Hex（16進数）エディタ。バイナリファイル閲覧用
        "ms-vscode.hexeditor"
    ],

    "unwantedRecommendations": []
}
